import grpc
from concurrent import futures
import time

# Server
class UserService(user_pb2_grpc.UserServiceServicer):
    def GetUser(self, request, context):
        # Unary — single request, single response
        return user_pb2.User(id=request.id, name="Alice", email="alice@ex.com")

    def ListUsers(self, request, context):
        # Server streaming — one request, multiple responses
        for i in range(10):
            yield user_pb2.User(id=i, name=f"User {i}")
            time.sleep(0.5)

    def CreateUser(self, request_iterator, context):
        # Client streaming — multiple requests, one response
        users = []
        for request in request_iterator:
            users.append(request.name)
        return user_pb2.CreateResponse(count=len(users))

    def Chat(self, request_iterator, context):
        # Bidirectional streaming
        for msg in request_iterator:
            yield user_pb2.ChatMessage(text=f"Echo: {msg.text}")

server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
user_pb2_grpc.add_UserServiceServicer_to_server(UserService(), server)
server.add_insecure_port('[::]:50051')
server.start()
