// Browser client (gRPC-Web)
import { RideServiceClient } from './generated/RideServiceClientPb';
import { RideRequest, TrackRequest } from './generated/ride_pb';

const client = new RideServiceClient('http://localhost:8080');

// Unary call
const request = new RideRequest();
request.setPickup('123 Main St');
request.setDestination('456 Oak Ave');

client.requestRide(request, {}, (err, response) => {
  if (err) {
    console.error(err.message);
    return;
  }
  console.log('Ride ID:', response.getRideId());
});

// Server streaming
const trackRequest = new TrackRequest();
trackRequest.setRideId('ride-123');

const stream = client.trackRide(trackRequest);
stream.on('data', (location) => {
  console.log(`Lat: ${location.getLat()}, Lng: ${location.getLng()}`);
});
stream.on('error', (err) => console.error(err));
stream.on('end', () => console.log('Tracking ended'));
