import grpc
from concurrent import futures
import chat_pb2
import chat_pb2_grpc

class ChatService(chat_pb2_grpc.ChatServiceServicer):
    def SendMessage(self, request, context):
        # Store message and return response
        msg_id = store_message(request)
        return chat_pb2.MessageResponse(
            message_id=msg_id, success=True
        )

    def StreamMessages(self, request, context):
        # Server streaming: yield messages as they arrive
        for message in get_messages_since(request.room_id, request.since_timestamp):
            yield message

    def Chat(self, request_iterator, context):
        # Bidirectional: read and write simultaneously
        for msg in request_iterator:
            broadcast(msg)
            yield msg
